import axios from 'axios';

const api = axios.create({
  baseURL: 'http://localhost:8080/api',
});

export const getItems = () => api.get('/items').catch(error => ({ error }));
export const createItem = (item) => api.post('/items', item).catch(error => ({ error }));
export const updateItem = (id, item) => api.put(`/items/${id}`, item).catch(error => ({ error }));
export const deleteItem = (id) => api.delete(`/items/${id}`).catch(error => ({ error }));
export const getCategories = () => api.get('/categories').catch(error => ({ error }));
export const createCategory = (category) => api.post('/categories', category).catch(error => ({ error }));
export const updateCategory = (id, category) => api.put(`/categories/${id}`, category).catch(error => ({ error }));
export const deleteCategory = (id) => api.delete(`/categories/${id}`).catch(error => ({ error }));
export const getPurchases = () => api.get('/purchases').catch(error => ({ error }));
export const createPurchase = (purchase) => api.post('/purchases', purchase).catch(error => ({ error }));
export const getSales = () => api.get('/sales').catch(error => ({ error }));
export const createSale = (sale) => api.post('/sales', sale).catch(error => ({ error }));
export const getBills = () => api.get('/bills').catch(error => ({ error }));
export const createBill = (bill) => api.post('/bills', bill).catch(error => ({ error }));
export const getBillPdf = (id) => api.get(`/bills/${id}/pdf`, { responseType: 'blob' }).catch(error => ({ error }));
export const getCompanies = () => api.get('/companies').catch(error => ({ error }));
export const createCompany = (company) => api.post('/companies', company).catch(error => ({ error }));
export const updateCompany = (id, company) => api.put(`/companies/${id}`, company).catch(error => ({ error }));
export const deleteCompany = (id) => api.delete(`/companies/${id}`).catch(error => ({ error }));
export const getExpenses = () => api.get('/expenses').catch(error => ({ error }));
export const createExpense = (expense) => api.post('/expenses', expense).catch(error => ({ error }));
export const getFocs = () => api.get('/focs').catch(error => ({ error }));
export const createFoc = (foc) => api.post('/focs', foc).catch(error => ({ error }));
export const getProfitLoss = () => api.get('/reports/profit-loss').catch(error => ({ error }));
